    const replaceOrder: number[] = order;

    // Function to calculate the number of valid substrings
    function countValidSubstrings(): number {
        let count: number = 0;
        for (let i = 0; i < n; i++) {
            if (replaced[i] > 0) {
                // Start a new substring from this position
                let len: number = 1;
                let start: number = i;
                while (start >= 0 && replaced[start] > 0) {
                    len++;
                    start--;
                }
                // The number of substrings starting at i and ending at j >= i
                count += len * (len + 1) / 2;
            }
        }
        return count;
    }

    // Check if the string is already active
    if (countValidSubstrings() >= k) {
        return -1;
    }

    // Try replacing each character in order
    for (let t = 0; t < n; t++) {
        const idx: number = replaceOrder[t];
        replaced[idx] = 1;
        if (countValidSubstrings() >= k) {
            return t;
        }
    }

    return -1;
}

